import React from 'react'
import { v4 as uuidv4 } from 'uuid';

export default function AppExample({ data }) {
    return (
        <div className={data.className}>
            <div className="aboutApp_container">
                <h2>
                    <a href={data.link}>{data.appName}</a>
                </h2>
                <div >
                    {data.about}
                </div>
            </div>
            <div className='appExample_footer'>
                <img className="AppExample_image" src={process.env.PUBLIC_URL + data.image} />
                <div className='tech_container'>
                    {data.technologies.map(img =>
                        <img key={uuidv4()} className="technolgies_image" src={process.env.PUBLIC_URL + img} />
                    )}
                </div>
                <a className="btn" href={data.link}>
                    Visit {data.appName} Website
                </a>
            </div>

        </div>
    )
}
